import json
import os
import re
import uuid
from dataclasses import dataclass, asdict
from typing import Optional, Dict, Any

import boto3
from botocore.config import Config


EMAIL_RE = re.compile(r"^[^@\s]+@[^@\s]+\.[^@\s]+$")
PHONE_RE = re.compile(r"^\+?[0-9\-\(\)\s]{7,20}$")


@dataclass
class Address:
    line1: str
    line2: Optional[str]
    city: str
    state: Optional[str]
    postal_code: str
    country: str


@dataclass
class UserDataMessage:
    user_id: str
    email: str
    phone_number: str
    address: Address
    full_name: Optional[str] = None


class SQSPublisher:
    def __init__(
        self,
        queue_url: str,
        region_name: Optional[str] = None,
        aws_access_key_id: Optional[str] = None,
        aws_secret_access_key: Optional[str] = None,
        aws_session_token: Optional[str] = None,
    ) -> None:
        self.queue_url = queue_url
        self.client = boto3.client(
            "sqs",
            region_name=region_name or os.getenv("AWS_REGION") or os.getenv("AWS_DEFAULT_REGION") or "us-east-1",
            aws_access_key_id=aws_access_key_id or os.getenv("AWS_ACCESS_KEY_ID"),
            aws_secret_access_key=aws_secret_access_key or os.getenv("AWS_SECRET_ACCESS_KEY"),
            aws_session_token=aws_session_token or os.getenv("AWS_SESSION_TOKEN"),
            config=Config(retries={"max_attempts": 10, "mode": "standard"}),
        )

    @staticmethod
    def _validate_email(email: str) -> None:
        if not EMAIL_RE.match(email):
            raise ValueError("Invalid email format")

    @staticmethod
    def _validate_phone(phone_number: str) -> None:
        if not PHONE_RE.match(phone_number):
            raise ValueError("Invalid phone number format")

    @staticmethod
    def _validate_address(address: Address) -> None:
        required = {
            "line1": address.line1,
            "city": address.city,
            "postal_code": address.postal_code,
            "country": address.country,
        }
        missing = [k for k, v in required.items() if not v or not str(v).strip()]
        if missing:
            raise ValueError(f"Missing required address fields: {', '.join(missing)}")

    def publish_user_data(self, message: UserDataMessage, deduplication_id: Optional[str] = None, group_id: Optional[str] = None) -> Dict[str, Any]:
        if not message.user_id or not str(message.user_id).strip():
            raise ValueError("user_id is required")

        self._validate_email(message.email)
        self._validate_phone(message.phone_number)
        self._validate_address(message.address)

        payload = asdict(message)
        body = json.dumps(payload, separators=(",", ":"), ensure_ascii=False)

        params: Dict[str, Any] = {
            "QueueUrl": self.queue_url,
            "MessageBody": body,
            "MessageAttributes": {
                "contains_pii": {
                    "DataType": "String",
                    "StringValue": "true",
                },
                "message_type": {
                    "DataType": "String",
                    "StringValue": "user_data",
                },
                "user_id": {
                    "DataType": "String",
                    "StringValue": message.user_id,
                },
            },
        }

        if queue_url_is_fifo(self.queue_url):
            params["MessageGroupId"] = group_id or "user-data"
            params["MessageDeduplicationId"] = deduplication_id or str(uuid.uuid4())

        return self.client.send_message(**params)


def queue_url_is_fifo(queue_url: str) -> bool:
    return queue_url.endswith(".fifo")


